/**
 * MedX trap accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Focus trap for modal and dialog surfaces.
 */
const TRAP_TOKENS = Object.freeze({
  primary: { value: "a11y-trap-primary", scope: "a11y" },
  secondary: { value: "a11y-trap-secondary", scope: "a11y" },
  muted: { value: "a11y-trap-muted", scope: "a11y" },
  accent: { value: "a11y-trap-accent", scope: "a11y" },
  surface: { value: "a11y-trap-surface", scope: "a11y" },
});

const TRAP_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const TRAP_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const trapRegistry = new Map();
const TRAP_listeners = new Set();
let TRAP_seq = 0;

function createTrapId(prefix = "medx-a11y-trap") {
  TRAP_seq += 1;
  return `${prefix}-${TRAP_seq}`;
}

function registerTrap(config = {}) {
  const entryId = config.id ?? createTrapId();
  const preset = TRAP_PRESETS[config.preset ?? "default"] ?? TRAP_PRESETS.default;
  const token = TRAP_TOKENS[config.token ?? preset.token] ?? TRAP_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: TRAP_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  trapRegistry.set(entryId, entry);
  notifyTrapListeners("register", entry);
  return entry;
}

function updateTrap(id, patch = {}) {
  const entry = trapRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyTrapListeners("update", entry);
  return entry;
}

function resolveTrap(id) {
  const entry = trapRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listTrapEntries(filter = {}) {
  let items = Array.from(trapRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onTrapEvent(listener) {
  TRAP_listeners.add(listener);
  return () => TRAP_listeners.delete(listener);
}

function notifyTrapListeners(type, entry) {
  for (const listener of TRAP_listeners) {
    try {
      listener({ type, entry, registrySize: trapRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:trap] listener error", err.message);
    }
  }
}

function getTrapMetrics() {
  const items = listTrapEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(TRAP_TOKENS).length,
    presets: Object.keys(TRAP_PRESETS).length,
  };
}

async function runMedxTrap() {
  console.log("[medx:ui:a11y:trap] runtime initialized");
  console.log(`[medx:ui:a11y:trap] tokens=${Object.keys(TRAP_TOKENS).length} presets=${Object.keys(TRAP_PRESETS).length}`);

  const events = [];
  onTrapEvent((e) => events.push(e.type));

  const domains = Object.keys(TRAP_SUPPLY_CHAIN);
  const presets = Object.keys(TRAP_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerTrap({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/trap" },
    });
  }

  const first = listTrapEntries()[0];
  if (first) updateTrap(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getTrapMetrics();
  const resolved = first ? resolveTrap(first.id) : null;

  console.log(`[medx:ui:a11y:trap] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:trap] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:trap] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:trap] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:trap] bootstrap complete");
}

module.exports = runMedxTrap;
